};

scwin.callbackPopUpNm1 = async function(rtnList) {
    if (rtnList != null) {
        if (rtnList[0] == "N/A") {
            ed_reqAcctDeptCd.setValue("");
            txt_reqAcctDeptNm.setValue("");
            scwin.hidVal_reqAcctDeptCd = "";
            return;
        }
        ed_reqAcctDeptCd.setValue(rtnList[0]);
